/* Minimal local HTMX-compatible helper for ReadeRSS forms/links used before full HTMX is vendored. */
(function () {
  function request(method, url, target, swap) {
    fetch(url, { method: method, headers: { "HX-Request": "true" } })
      .then((response) => response.text())
      .then((html) => {
        const node = document.querySelector(target);
        if (!node) return;
        if (swap === "outerHTML") node.outerHTML = html;
        else node.innerHTML = html;
      });
  }
  document.addEventListener("click", function (event) {
    const trigger = event.target.closest("[hx-get],[hx-post]");
    if (!trigger) return;
    const url = trigger.getAttribute("hx-get") || trigger.getAttribute("hx-post");
    const target = trigger.getAttribute("hx-target");
    if (!url || !target) return;
    event.preventDefault();
    request(trigger.hasAttribute("hx-post") ? "POST" : "GET", url, target, trigger.getAttribute("hx-swap") || "innerHTML");
  });
})();
